import { i as getImages } from "../../../chunks/docker.js";
//#region src/routes/images/+page.server.ts
var load = async () => {
	return { images: (await getImages()).map((img) => ({
		id: img.Id,
		tags: img.RepoTags || ["<none>"],
		size: img.Size,
		created: img.Created
	})) };
};
//#endregion
export { load };
